class Solution:
    def solve(self, head: Optional[ListNode]) -> Optional[ListNode]:
        seen = set()
        current = head
        while current:
            next_node = current.next
            while next_node:
                if next_node.val in seen:
                    current.next = next_node.next
                else:
                    seen.add(next_node.val)
                    current = current.next
                next_node = next_node.next
            return head


# Helper class to create a linked list
class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

# Read input from sys.stdin
def read_input():
    return [int(x) for x in input().split()]

# Read input from sys.stdin
def main():
    head = None
    values = read_input()
    for v in values:
        if not head:
            head = ListNode(v)
        else:
            current = head
            while current.next:
                current = current.next
            current.next = ListNode(v)
    head = removeDuplicates(head)
    print_node(head)

# Helper function to print the linked list
def print_node(head):
    while head:
        print(head.val, end=' -> ' if head.next else ' -> None')
        head = head.next

        # Call the solution function
        solution = Solution()
        solution.solve(head)
        print()
if __name__ == '__main__':
    main()

